@deps rm

# Invariants & contracts
  @invariant  fx node id == its fxId (from instantiateFxOnScratch); source node id == track guid  @ 4
  @invariant  CU bridges arrive at the applier with nil fxId; reconcileFXChain mints them  @ 5
  @invariant  fxId is the stable bridge identity; snapshot/targetState match fxOrder by it  @ 6
  @invariant  wm deletes an FX instance only when its owning node or CU bridge leaves the graph  @ 7
  @invariant  trackKey changes are moves; TrackFX_CopyToTrack(is_move=true) preserves plugin state  @ 8
  @invariant  authoring via wm:mutate — validate+swap+fire; REAPER realises via reconcile.  @ 16
  @invariant  master is graph.nodes['master']; readGraph seeds it; DAG.validate enforces singleton.  @ 17
  @invariant  scratch is owned by scratch.lua (scratch.id/track); wm parks fx there  @ 18
  @invariant  a newTrack carries its trackKey in its metadata; snapshot recovers addressing  @ 19
  @invariant  scratch hosts FX with no compile-graph track — disconnected or lowered-parked  @ 20
  @contract  one Undo block around instantiate + mutate; stamps fxId on the new fx-node  @ 530
  @contract  generators (io.ins==0) also spawn sourceTrack + source-node + midi edge  @ 531
  @contract  a generator with audio outs also wires straight to master  @ 532
  @contract  returns fx-node id + sourceGuid (nil if none); nil+err on validate/refusal  @ 533

# Shapes
  @shape  snapshotPinMap = { ins={[port]={pair,...}}, outs={[port]={pair,...}} }  @ 9
  @shape  snapshotSend = { to=trackKey, kind='audio'|'midi', gain?=number, srcChan=int, dstChan=int, pos='preFx'|'preFader'|'postFader' }  @ 10
  @shape  snapshotFxOrigin = {kind='bracketIn'|'bracketOut',id=string}|{kind='merge',consumer=string,trackKey=trackKey}  -- CU bridges only; node fx carry their fxId as id  @ 11
  @shape  snapshotFxEntry = { id?=string, ident=string, name?=string, ins?=int, outs?=int, params?=table, origin?=snapshotFxOrigin, midi?={inBus=int,outBus=int,inDisabled=bool,outDisabled=bool}, pinMaps?=snapshotPinMap, busAware?=bool }  -- ins/outs are audio pair counts, for read; name feeds fxDisplay  @ 12
  @shape  wiringSnapshot = { [trackKey] = { trackKind='sourceTrack'|'newTrack'|'master'|'scratch', id?=string, parent?=guid, nchan?=int, hasMidiTake?=bool, mainSend={on=bool,gain?,tgtOffset?,nchan?}, fx=snapshotFxEntry[], sends=snapshotSend[] } }; rm:tracks() record + trackKey overlay (full chain, no ownership filter). see docs/wiringManager.md § wiringSnapshot.  @ 13
  @shape  wiringOp = { op='createTrack'|'deleteTrack'|'setFXChain'|'setMainSend'|'setSends'|'setNchan'|'setPinMaps'|'moveFxAcrossTracks', ... }  @ 14
  @shape  busRecord = { pos={x,y}, orient='V'|'H', ext={lo,hi}?, ins={{node,port,gain?},…}, outs={…}, trackId? } — ext = hand-sized bar span (axial offsets from pos); taps mirror the node's edges; trackId iff matrix  @ 756
  @shape  routing[edgeIdx] = {kind='mergeCU',consumerId,trackKey,slot} | {kind='mainSend',cls} | {kind='send',from,to} | {kind='product',crossings={{target,parts=int[]},…}}  @ 1898

